194→const TASK_PROMPT = `
195→1 - Understand and write your understanding of every single and 
196→each WORKFLOW AND CRITICAL statement.
197→2 - Understand and write your understanding of the work in progress
198→  described in progress.txt and compared with the actual files.
199→
200→WORKFLOW:
201→0. Understand Project
202→1. Read ./.claude/progress.txt and identify the most important pending task;
203→   - Specific task prioritization is indicated/tagged/prefixed with '[P'+number+']'
204→   - Tasks tagged with '[P0]' must be done before anything else.
205→   - Tasks tagged with P bigger than 999 (e.g. '[P1000]'), are low-priority 
206→   tasks, they should be done when possible, but they must be done 
207→   (they are not ignorable); If the task takes longer and there are other 
208→   non-low-priority tasks, document progress and revert the status to "- [ ]".
209→   
210→2. If NO pending tasks exist, plan next improvements, add tasks and stop
211→3. If there are tasks, mark it as IN_PROGRESS and then sequentially run:
212→   - Evaluate scope: if the task involves more than ~3 files or multiple concerns,
213→      break it into smaller sub-tasks in progress.txt BEFORE starting. Each sub-task
214→      must be completable in a single iteration (small, atomic, committable change).
215→   - Execute task
216→   - Run 'bun run check' and fix found issues.     
217→   - Launch 1 review agents to deeply review the work, giving
218→      the entire context of the task, simulating pull request.
219→   - Review output and consider improvements
220→   - Implement corrections if needed
221→   - Update progress.txt marking task as completed
222→   - Commit task changes (not include unrelated code)
223→   - Output status block (see below)
224→   - Stop
225→
226→CRITICAL:
227→- ALL tasks and instructions are deliberate. 
228→- No task is optional.
229→- If more work is necessary, add a new task to the file, set "exit": false, and Stop
230→- Never remove tasks, unless to update status;
231→- Never include workarounds and add tasks to fix all you found ('as any' for example is a workaround)
232→- No task should be submitted as "look reasonable." 
233→- Every task must be delivered with professional quality, without any makeshift solutions.
234→- For tasks with visual parts, full visual and interaction tests with Playwright MCP are required.
235→- Never consider any mistake or error to be expected or acceptable.- Never consider any mistake or error to be expected or acceptable.
236→- Never trust project comments or documentation without confirming on actual 
237→code.
238→
239→--------------------------------------------------------------------------------
240→
241→OUTPUT STATUS (REQUIRED at end of EVERY response):
242→You MUST output this exact format at the END of your response:
243→
244→RALPH_STATUS: { "exit": <true if ALL tasks done, false otherwise>, "task": "<completed task name>", "remaining": <number of pending tasks> }
245→
246→Examples:
247→- Task completed but more remain: RALPH_STATUS: { "exit": false, "task": "Create usePoints hook", "remaining": 5 }
248→- ALL tasks completed: RALPH_STATUS: { "exit": true, "task": "Delete Redux files", "remaining": 0 }
249→
250→`;
251→
252→interface ContentBlock {
253→  type: 'text' | 'tool_use' | 'tool_result';
254→  text?: string;
255→  name?: string;
256→  input?: unknown;
257→  content?:
258→    | string
259→    | Array<{
260→        type: string;
261→        text?: string;
262→      }>;
263→}
264→
265→interface StreamMessage {
266→  type: 'system' | 'assistant' | 'user' | 'result' | 'stream_event' | 'message';
267→  subtype?: string;
268→  role?: 'assistant' | 'user';
269→  event?: {
270→    type: string;
271→    delta?: {
272→      type: string;
273→      text?: string;
274→    };
275→  };
276→  result?: string;
277→  message?: {
278→    role?: string;
279→    content?: ContentBlock[];
280→  };
281→  content?: ContentBlock[];
282→}
283→
284→interface RalphStatus {
285→  exit: boolean;
286→  task: string;
287→  remaining: number;
288→}
289→
290→function parseRalphStatus(output: string): RalphStatus | null {
291→  const marker = output.lastIndexOf('RALPH_STATUS:');
292→  if (marker === -1) return null;
293→
294→  const jsonStart = output.indexOf('{', marker);
295→  if (jsonStart === -1) return null;
296→
297→  let depth = 0;
298→  for (let i = jsonStart; i < output.length; i++) {
299→    if (output[i] === '{') depth++;
300→    if (output[i] === '}') depth--;
301→    if (depth === 0) {
302→      try {
303→        const parsed = JSON.parse(output.slice(jsonStart, i + 1));
304→        if (typeof parsed.exit === 'boolean') {
305→          return parsed as RalphStatus;
306→        }
307→      } catch {}
308→      return null;
309→    }
310→  }
311→  return null;
312→}
313→
314→let currentProc: ReturnType<typeof Bun.spawn> | null = null;
315→
316→function killCurrentProc(): void {
317→  if (!currentProc) return;
318→  try {
319→    currentProc.kill();
320→  } catch {}
321→}
322→
323→async function checkDependencies(): Promise<void> {
324→  const result = await Bun.$`which claude`.quiet().nothrow();
325→  if (result.exitCode !== 0) {
326→    syslog("ERROR: 'claude' CLI not found. Install Claude Code.", 'red');
327→    process.exit(1);
328→  }
329→
330→  if (!(await Bun.file(CONFIG.progressFile).exists())) {
331→    syslog(`ERROR: Progress file not found: ${CONFIG.progressFile}`, 'red');
332→    process.exit(1);
333→  }
334→}
335→
336→interface IterationResult {
337→  output: string;
338→  exitCode: number;
339→  timedOut: boolean;
340→}
341→
342→async function runIteration(): Promise<IterationResult> {
343→  syslog('Executing Claude Code...');
344→
345→  const proc = Bun.spawn(
346→    [
347→      'claude',
348→      '-p',
349→      TASK_PROMPT,
350→      '--verbose',
351→      '--debug',
352→      '--dangerously-skip-permissions',
353→      '--output-format',
354→      'stream-json',
355→      '--include-partial-messages',
356→      '--model=opus',
357→    ],
358→    {
359→      cwd: process.cwd(),
360→      env: process.env,
361→      stdout: 'pipe',
362→      stderr: 'inherit',
363→    },
364→  );
365→
366→  currentProc = proc;
367→
368→  const chunks: string[] = [];
369→  let timedOut = false;
370→  const decoder = new TextDecoder();
371→  let buffer = '';
372→  let blockHasContent = false;
373→
374→  const timeoutId = setTimeout(() => {
375→    timedOut = true;
376→    syslog('Iteration timeout reached. Killing process...', 'yellow');
377→    killCurrentProc();
378→  }, CONFIG.iterationTimeout);
379→
380→  const reader = proc.stdout.getReader();
381→
382→  try {
383→    while (true) {
384→      const { done, value } = await reader.read();
385→      if (done) break;
386→
387→      buffer += decoder.decode(value, { stream: true });
388→
389→      const lines = buffer.split('\n');
390→      buffer = lines.pop() || '';
391→
392→      for (const line of lines) {
393→        if (!line.trim()) continue;
394→
395→        let msg: StreamMessage;
396→        try {
397→          msg = JSON.parse(line);
398→        } catch {
399→          continue;
400→        }
401→
402→        if (msg.type === 'stream_event') {
403→          const evt = msg.event;
404→          if (!evt) continue;
405→
406→          if (evt.type === 'content_block_start') {
407→            blockHasContent = false;
408→          } else if (evt.type === 'content_block_delta') {
409→            const text = evt.delta?.text;
410→            if (text) {
411→              print(text);
412→              chunks.push(text);
413→              blockHasContent = true;
414→            }
415→          } else if (evt.type === 'content_block_stop' && blockHasContent) {
416→            print('\n');
417→            chunks.push('\n');
418→            blockHasContent = false;
419→          }
420→          continue;
421→        }
422→
423→        if (msg.type === 'assistant' || msg.type === 'message') {
424→          // Content already streamed via content_block_delta events.
425→          // Only print here as fallback if no streaming occurred.
426→          const blocks = msg.message?.content ?? msg.content;
427→          if (!Array.isArray(blocks)) continue;
428→
429→          for (const block of blocks) {
430→            if (block.type === 'text' && block.text && chunks.length === 0) {
431→              print(block.text);
432→              chunks.push(block.text);
433→              print('\n');
434→              chunks.push('\n');
435→            }
436→          }
437→          continue;
438→        }
439→
440→        if (msg.type === 'user') {
441→          const blocks = msg.message?.content ?? msg.content;
442→          if (!Array.isArray(blocks)) continue;
443→
444→          for (const block of blocks) {
445→            //
446→            // Handling tool result
447→            if (block.type === 'tool_result' && block.content) {
448→              const rawContent =
449→                typeof block.content === 'string'
450→                  ? block.content
451→                  : block.content
452→                      .map(c => c.text ?? '')
453→                      .filter(Boolean)
454→                      .join('\n');
455→
456→              if (!rawContent) continue;
457→
458→              let trimmed = rawContent.trim().slice(0, 320);
459→
460→              const toolResult =
461→                trimmed && trimmed !== rawContent
462→                  ? trimmed.split('\n').slice(0, 3).join('\n') + ' [...]'
463→                  : rawContent;
464→
465→              println(`\n${toolResult.trimEnd()}\n`, 'blackBright');
466→              chunks.push('\n', rawContent, '\n');
467→            }
468→          }
469→          continue;
470→        }
471→
472→        if (msg.type === 'result' && msg.result) {
473→          if (chunks.length === 0) {
474→            chunks.push(msg.result);
475→          }
476→        }
477→      }
478→    }
479→
480→    if (buffer.trim()) {
481→      try {
482→        const msg: StreamMessage = JSON.parse(buffer);
483→        if (msg.type === 'result' && msg.result && chunks.length === 0) {
484→          chunks.push(msg.result);
485→        }
486→      } catch {}
487→    }
488→  } finally {
489→    clearTimeout(timeoutId);
490→    reader.releaseLock();
491→    currentProc = null;
492→    logBuffer.flush();
493→  }
494→
495→  const output = chunks.join('');
496→
497→  if (timedOut) {
498→    return {
499→      output,
500→      exitCode: 124,
501→      timedOut: true,
502→    };
503→  }
504→
505→  const exitCode = await proc.exited;
506→  println();
507→  return {
508→    output,
509→    exitCode,
510→    timedOut: false,
511→  };
512→}
513→
514→function printHeader(): void {
515→  println();
516→  println('==========================================', 'blue');
517→  println('   Ralph Loop - Bun.js Edition', 'blue');
518→  println('==========================================', 'blue');
519→  println(`Max iterations: ${chalk.yellow(CONFIG.maxIterations)}`);
520→  println(`Log dir:        ${chalk.yellow(LOG_DIR)}`);
521→  println(
522→    `Iter delay:     ${chalk.yellow(`${CONFIG.delayBetweenIterations / 1_000}s`)}`,
523→  );
524→  println(
525→    `Iter timeout:   ${chalk.yellow(`${CONFIG.iterationTimeout / 60_000}min`)}`,
526→  );
527→  println();
528→}
529→
530→async function main(): Promise<void> {
531→  let cleanupCalled = false;
532→
533→  const cleanup = (signal: string) => {
534→    if (cleanupCalled) return;
535→    cleanupCalled = true;
536→    hooks.cleanup.call(signal);
537→    println();
538→    syslog(`Interrupted by ${signal}. Cleaning up...`);
539→    killCurrentProc();
540→    logBuffer.dispose();
541→    process.exit(signal === 'SIGINT' ? 130 : 143);
542→  };
543→
544→  process.on('SIGINT', () => cleanup('SIGINT'));
545→  process.on('SIGTERM', () => cleanup('SIGTERM'));
546→
547→  await checkDependencies();
548→
549→  printHeader();
550→  syslog('Starting automated task loop...');
551→
552→  await hooks.loopStart.promise(CONFIG);
553→
554→  let consecutiveFailures = 0;
555→  let iteration = 0;
556→  const BACKOFF_BASE_MS = 60_000;
557→  const BACKOFF_MAX_MS = 5 * 60 * 60_000;
558→
559→  while (iteration < CONFIG.maxIterations) {
560→    const attemptNum = iteration + 1;
561→    logBuffer.startNewFile(logFilePath(`iter-${attemptNum}`));
562→
563→    const iterCtx: IterationContext = {
564→      iteration: attemptNum,
565→      maxIterations: CONFIG.maxIterations,
566→      logPath: logBuffer.currentPath(),
567→    };
568→
569→    println();
570→    println('==========================================', 'green');
571→    syslog(`Iteration #${attemptNum} / ${CONFIG.maxIterations}`, 'green');
572→    syslog(`Log: ${logBuffer.currentPath()}`, 'green');
573→    println('==========================================', 'green');
574→    println();
575→
576→    await hooks.iterationStart.promise(iterCtx);
577→
578→    const result = await runIteration();
579→    const { output, exitCode, timedOut } = result;
580→
581→    if (exitCode === 0) {
582→      syslog('Claude Code completed successfully', 'green');
583→      consecutiveFailures = 0;
584→      await hooks.iterationSuccess.promise(result, iterCtx);
585→    } else if (timedOut) {
586→      syslog(
587→        'Iteration timed out — progress may persist in progress.txt',
588→        'yellow',
589→      );
590→      consecutiveFailures = 0;
591→      hooks.iterationTimeout.call(result, iterCtx);
592→    } else {
593→      syslog(`Claude Code exited with code ${exitCode}`, 'yellow');
594→      consecutiveFailures++;
595→
596→      const failCtx: FailureContext = {
597→        ...iterCtx,
598→        exitCode,
599→        consecutiveFailures,
600→      };
601→      await hooks.iterationFailure.promise(result, failCtx);
602→
603→      const backoffMs = Math.min(
604→        BACKOFF_BASE_MS * Math.pow(2, consecutiveFailures - 1),
605→        BACKOFF_MAX_MS,
606→      );
607→      const backoffMin = (backoffMs / 60_000).toFixed(1);
608→
609→      const backoffCtx: BackoffContext = { ...failCtx, backoffMs };
610→      const skipBackoff = hooks.backoff.call(backoffCtx);
611→
612→      if (skipBackoff) {
613→        syslog('Backoff skipped by hook', 'yellow');
614→      } else {
615→        println();
616→        println('==========================================', 'yellow');
617→        syslog(
618→          `${consecutiveFailures} consecutive failure(s) — retrying in ${backoffMin}min`,
619→          'yellow',
620→        );
621→        println('==========================================', 'yellow');
622→        await Bun.sleep(backoffMs);
623→      }
624→      continue;
625→    }
626→
627→    iteration++;
628→
629→    const rawStatus = parseRalphStatus(output);
630→    const status = hooks.statusParsed.call(rawStatus, output);
631→    const taskSlug = status
632→      ? slugify(status.task)
633→      : timedOut
634→        ? 'timeout'
635→        : 'no-status';
636→    logBuffer.renameFile(logFilePath(taskSlug));
637→
638→    if (status?.exit) {
639→      await hooks.allTasksComplete.promise(status, iteration);
640→      println();
641→      println('==========================================', 'green');
642→      syslog('ALL TASKS COMPLETED!', 'green');
643→      syslog(`Final task:      ${status.task}`, 'green');
644→      syslog(`Remaining:       ${status.remaining}`, 'green');
645→      syslog(`Total iterations: ${iteration}`, 'green');
646→      println('==========================================', 'green');
647→      logBuffer.dispose();
648→      process.exit(0);
649→    }
650→
651→    if (status) {
652→      await hooks.taskComplete.promise(status, iterCtx);
653→      syslog(
654→        `Task done: "${status.task}" — ${status.remaining} remaining`,
655→        'blue',
656→      );
657→    } else if (!timedOut && exitCode === 0) {
658→      syslog(
659→        'Warning: No RALPH_STATUS found in output. Claude may not have followed the protocol.',
660→        'yellow',
661→      );
662→    }
663→
664→    if (iteration < CONFIG.maxIterations) {
665→      const delaySec = CONFIG.delayBetweenIterations / 1_000;
666→      println();
667→      syslog(`Waiting ${delaySec}s before next iteration...`);
668→      await Bun.sleep(CONFIG.delayBetweenIterations);
669→    }
670→  }
671→
672→  hooks.loopEnd.call(iteration);
673→
674→  println();
675→  println('==========================================', 'red');
676→  syslog(`MAX ITERATIONS REACHED (${CONFIG.maxIterations})`, 'red');
677→  syslog('Loop stopped — tasks may still be pending', 'red');
678→  println('==========================================', 'red');
679→  logBuffer.dispose();
680→  process.exit(1);
681→}
682→
683→main();
