102→	T,
103→	R,
104→	AdditionalOptions = UnsetAdditionalOptions
105→> extends Hook<T, R, AdditionalOptions> {
106→	tapAsync(
107→		options: string | (Tap & IfSet<AdditionalOptions>),
108→		fn: (...args: Append<AsArray<T>, InnerCallback<Error, R>>) => void
109→	): void;
110→	tapPromise(
111→		options: string | (Tap & IfSet<AdditionalOptions>),
112→		fn: (...args: AsArray<T>) => Promise<R>
113→	): void;
114→}
